<template>
	<view v-if="isShow" ref="ani" :animation="animationData" :class="customClass" :style="transformStyles" @click="onClick"><slot></slot></view>
</template>

<script>
import { createAnimation } from './createAnimation'

/**
 * Transition ่ฟๆธกๅจ็ป
 * @description ็ฎๅ่ฟๆธกๅจ็ป็ปไปถ
 * @tutorial https://ext.dcloud.net.cn/plugin?id=985
 * @property {Boolean} show = [false|true] ๆงๅถ็ปไปถๆพ็คบๆ้่
 * @property {Array|String} modeClass = [fade|slide-top|slide-right|slide-bottom|slide-left|zoom-in|zoom-out] ่ฟๆธกๅจ็ป็ฑปๅ
 *  @value fade ๆธ้ๆธๅบ่ฟๆธก
 *  @value slide-top ็ฑไธ่ณไธ่ฟๆธก
 *  @value slide-right ็ฑๅณ่ณๅทฆ่ฟๆธก
 *  @value slide-bottom ็ฑไธ่ณไธ่ฟๆธก
 *  @value slide-left ็ฑๅทฆ่ณๅณ่ฟๆธก
 *  @value zoom-in ็ฑๅฐๅฐๅคง่ฟๆธก
 *  @value zoom-out ็ฑๅคงๅฐๅฐ่ฟๆธก
 * @property {Number} duration ่ฟๆธกๅจ็ปๆ็ปญๆถ้ด
 * @property {Object} styles ็ปไปถๆ ทๅผ๏ผๅ css ๆ ทๅผ๏ผๆณจๆๅธฆโ-โ่ฟๆฅ็ฌฆ็ๅฑๆง้่ฆไฝฟ็จๅฐ้ฉผๅณฐๅๆณๅฆ๏ผ`backgroundColor:red`
 */
export default {
	name: 'uniTransition',
	emits:['click','change'],
	props: {
		show: {
			type: Boolean,
			default: false
		},
		modeClass: {
			type: [Array, String],
			default() {
				return 'fade'
			}
		},
		duration: {
			type: Number,
			default: 300
		},
		styles: {
			type: Object,
			default() {
				return {}
			}
		},
		customClass:{
			type: String,
			default: ''
		}
	},
	data() {
		return {
			isShow: false,
			transform: '',
			opacity: 1,
			animationData: {},
			durationTime: 300,
			config: {}
		}
	},
	watch: {
		show: {
			handler(newVal) {
				if (newVal) {
					this.open()
				} else {
					// ้ฟๅไธๆฅๅฐฑๆง่ก close,ๅฏผ่ดๅจ็ป้ไนฑ
					if (this.isShow) {
						this.close()
					}
				}
			},
			immediate: true
		}
	},
	computed: {
		// ็ๆๆ ทๅผๆฐๆฎ
		stylesObject() {
			let styles = {
				...this.styles,
				'transition-duration': this.duration / 1000 + 's'
			}
			let transform = ''
			for (let i in styles) {
				let line = this.toLine(i)
				transform += line + ':' + styles[i] + ';'
			}
			return transform
		},
		// ๅๅงๅๅจ็ปๆกไปถ
		transformStyles() {
			return 'transform:' + this.transform + ';' + 'opacity:' + this.opacity + ';' + this.stylesObject
		}
	},
	created() {
		// ๅจ็ป้ป่ฎค้็ฝฎ
		this.config = {
			duration: this.duration,
			timingFunction: 'ease',
			transformOrigin: '50% 50%',
			delay: 0
		}
		this.durationTime = this.duration
	},
	methods: {
		/**
		 *  ref ่งฆๅ ๅๅงๅๅจ็ป
		 */
		init(obj = {}) {
			if (obj.duration) {
				this.durationTime = obj.duration
			}
			this.animation = createAnimation(Object.assign(this.config, obj),this)
		},
		/**
		 * ็นๅป็ปไปถ่งฆๅๅ่ฐ
		 */
		onClick() {
			this.$emit('click', {
				detail: this.isShow
			})
		},
		/**
		 * ref ่งฆๅ ๅจ็ปๅ็ป
		 * @param {Object} obj
		 */
		step(obj, config = {}) {
			if (!this.animation) return
			for (let i in obj) {
				try {
					if(typeof obj[i] === 'object'){
						this.animation[i](...obj[i])
					}else{
						this.animation[i](obj[i])
					}
				} catch (e) {
					console.error(`ๆนๆณ ${i} ไธๅญๅจ`)
				}
			}
			this.animation.step(config)
			return this
		},
		/**
		 *  ref ่งฆๅ ๆง่กๅจ็ป
		 */
		run(fn) {
			if (!this.animation) return
			this.animation.run(fn)
		},
		// ๅผๅง่ฟๅบฆๅจ็ป
		open() {
			clearTimeout(this.timer)
			this.transform = ''
			this.isShow = true
			let { opacity, transform } = this.styleInit(false)
			if (typeof opacity !== 'undefined') {
				this.opacity = opacity
			}
			this.transform = transform
			// ็กฎไฟๅจๆๆ ทๅผๅทฒ็ป็ๆๅ๏ผๆง่กๅจ็ป๏ผๅฆๆไธๅ  nextTick ๏ผไผๅฏผ่ด wx ๅจ็ปๆง่กๅผๅธธ
			this.$nextTick(() => {
				// TODO ๅฎๆถๅจไฟ่ฏๅจ็ปๅฎๅจๆง่ก๏ผ็ฎๅๆไบ้ฎ้ข๏ผๅ้ขไผๅๆถๅฎๆถๅจ
				this.timer = setTimeout(() => {
					this.animation = createAnimation(this.config, this)
					this.tranfromInit(false).step()
					this.animation.run()
					this.$emit('change', {
						detail: this.isShow
					})
				}, 20)
			})
		},
		// ๅณ้ญ่ฟๅบฆๅจ็ป
		close(type) {
			if (!this.animation) return
			this.tranfromInit(true)
				.step()
				.run(() => {
					this.isShow = false
					this.animationData = null
					this.animation = null
					let { opacity, transform } = this.styleInit(false)
					this.opacity = opacity || 1
					this.transform = transform
					this.$emit('change', {
						detail: this.isShow
					})
				})
		},
		// ๅค็ๅจ็ปๅผๅงๅ็้ป่ฎคๆ ทๅผ
		styleInit(type) {
			let styles = {
				transform: ''
			}
			let buildStyle = (type, mode) => {
				if (mode === 'fade') {
					styles.opacity = this.animationType(type)[mode]
				} else {
					styles.transform += this.animationType(type)[mode] + ' '
				}
			}
			if (typeof this.modeClass === 'string') {
				buildStyle(type, this.modeClass)
			} else {
				this.modeClass.forEach(mode => {
					buildStyle(type, mode)
				})
			}
			return styles
		},
		// ๅค็ๅ็ฝฎ็ปๅๅจ็ป
		tranfromInit(type) {
			let buildTranfrom = (type, mode) => {
				let aniNum = null
				if (mode === 'fade') {
					aniNum = type ? 0 : 1
				} else {
					aniNum = type ? '-100%' : '0'
					if (mode === 'zoom-in') {
						aniNum = type ? 0.8 : 1
					}
					if (mode === 'zoom-out') {
						aniNum = type ? 1.2 : 1
					}
					if (mode === 'slide-right') {
						aniNum = type ? '100%' : '0'
					}
					if (mode === 'slide-bottom') {
						aniNum = type ? '100%' : '0'
					}
				}
				this.animation[this.animationMode()[mode]](aniNum)
			}
			if (typeof this.modeClass === 'string') {
				buildTranfrom(type, this.modeClass)
			} else {
				this.modeClass.forEach(mode => {
					buildTranfrom(type, mode)
				})
			}

			return this.animation
		},
		animationType(type) {
			return {
				fade: type ? 1 : 0,
				'slide-top': `translateY(${type ? '0' : '-100%'})`,
				'slide-right': `translateX(${type ? '0' : '100%'})`,
				'slide-bottom': `translateY(${type ? '0' : '100%'})`,
				'slide-left': `translateX(${type ? '0' : '-100%'})`,
				'zoom-in': `scaleX(${type ? 1 : 0.8}) scaleY(${type ? 1 : 0.8})`,
				'zoom-out': `scaleX(${type ? 1 : 1.2}) scaleY(${type ? 1 : 1.2})`
			}
		},
		// ๅ็ฝฎๅจ็ป็ฑปๅไธๅฎ้ๅจ็ปๅฏนๅบๅญๅธ
		animationMode() {
			return {
				fade: 'opacity',
				'slide-top': 'translateY',
				'slide-right': 'translateX',
				'slide-bottom': 'translateY',
				'slide-left': 'translateX',
				'zoom-in': 'scale',
				'zoom-out': 'scale'
			}
		},
		// ้ฉผๅณฐ่ฝฌไธญๆจช็บฟ
		toLine(name) {
			return name.replace(/([A-Z])/g, '-$1').toLowerCase()
		}
	}
}
</script>

